#!/usr/bin/env node

import { comparePdfs, formatDiff } from '../src/index.js';
import { existsSync } from 'fs';
import { resolve } from 'path';

/**
 * @typedef {Object} CliOptions
 * @property {boolean} ignoreWhitespace - Ignore whitespace differences
 * @property {boolean} ignoreCase - Ignore case differences
 * @property {boolean} showUnchanged - Show unchanged lines in output
 * @property {number} context - Number of context lines around changes
 * @property {boolean} color - Enable color output
 * @property {'char'|'word'|'line'} mode - Diff mode
 * @property {boolean} help - Show help message
 * @property {boolean} version - Show version
 */

/**
 * Display help message
 */
function showHelp() {
  console.log(`
pdfdiff - Compare PDF files and show differences

Usage: pdfdiff <pdf1> <pdf2> [options]

Arguments:
  pdf1                  First PDF file to compare
  pdf2                  Second PDF file to compare

Options:
  -i, --ignore-whitespace    Ignore whitespace differences
  -c, --ignore-case          Ignore case differences  
  -u, --show-unchanged       Show unchanged lines in output
  -m, --mode <mode>          Diff mode: char (default), word, or line
  --context <number>         Number of context lines around changes (default: 3)
  --no-color                 Disable color output
  -h, --help                 Show this help message
  -v, --version              Show version number

Examples:
  pdfdiff file1.pdf file2.pdf
  pdfdiff file1.pdf file2.pdf --ignore-whitespace
  pdfdiff file1.pdf file2.pdf --mode word
  pdfdiff file1.pdf file2.pdf --mode line --show-unchanged --context 5
  pdfdiff file1.pdf file2.pdf --no-color
`);
}

/**
 * Display version information
 */
function showVersion() {
  console.log('pdfdiff version 1.0.0');
}

/**
 * Parse command line arguments
 * @param {string[]} args - Command line arguments
 * @returns {Object} Parsed arguments and options
 */
function parseArgs(args) {
  const result = {
    files: [],
    options: {
      ignoreWhitespace: false,
      ignoreCase: false,
      showUnchanged: false,
      context: 3,
      color: true,
      mode: 'char',
      help: false,
      version: false
    }
  };

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];
    
    switch (arg) {
      case '-h':
      case '--help':
        result.options.help = true;
        break;
      case '-v':
      case '--version':
        result.options.version = true;
        break;
      case '-i':
      case '--ignore-whitespace':
        result.options.ignoreWhitespace = true;
        break;
      case '-c':
      case '--ignore-case':
        result.options.ignoreCase = true;
        break;
      case '-u':
      case '--show-unchanged':
        result.options.showUnchanged = true;
        break;
      case '-m':
      case '--mode':
        if (i + 1 < args.length) {
          const modeValue = args[i + 1].toLowerCase();
          if (!['char', 'word', 'line'].includes(modeValue)) {
            console.error('Error: --mode must be one of: char, word, line');
            process.exit(1);
          }
          result.options.mode = modeValue;
          i++; // Skip next argument as it's the value
        } else {
          console.error('Error: --mode requires a value');
          process.exit(1);
        }
        break;
      case '--context':
        if (i + 1 < args.length) {
          const contextValue = parseInt(args[i + 1]);
          if (isNaN(contextValue) || contextValue < 0) {
            console.error('Error: --context requires a non-negative number');
            process.exit(1);
          }
          result.options.context = contextValue;
          i++; // Skip next argument as it's the value
        } else {
          console.error('Error: --context requires a value');
          process.exit(1);
        }
        break;
      case '--no-color':
        result.options.color = false;
        break;
      default:
        if (arg.startsWith('-')) {
          console.error(`Error: Unknown option '${arg}'`);
          console.error('Use --help for usage information');
          process.exit(1);
        } else {
          result.files.push(arg);
        }
        break;
    }
  }

  return result;
}

/**
 * Validate file paths
 * @param {string[]} files - Array of file paths
 * @returns {boolean} Whether all files are valid
 */
function validateFiles(files) {
  if (files.length !== 2) {
    console.error('Error: Exactly two PDF files must be provided');
    console.error('Use --help for usage information');
    return false;
  }

  for (const file of files) {
    const fullPath = resolve(file);
    if (!existsSync(fullPath)) {
      console.error(`Error: File not found: ${file}`);
      return false;
    }
    
    if (!file.toLowerCase().endsWith('.pdf')) {
      console.warn(`Warning: ${file} does not have a .pdf extension`);
    }
  }

  return true;
}

/**
 * Main CLI function
 */
async function main() {
  const args = process.argv.slice(2);
  const { files, options } = parseArgs(args);

  if (options.help) {
    showHelp();
    process.exit(0);
  }

  if (options.version) {
    showVersion();
    process.exit(0);
  }

  if (!validateFiles(files)) {
    process.exit(1);
  }

  try {
    console.log(`Comparing ${files[0]} and ${files[1]}...`);
    
    const startTime = Date.now();
    const diffResult = await comparePdfs(files[0], files[1], {
      ignoreWhitespace: options.ignoreWhitespace,
      ignoreCase: options.ignoreCase,
      mode: options.mode
    });
    const endTime = Date.now();

    const formattedDiff = await formatDiff(diffResult, {
      showUnchanged: options.showUnchanged,
      context: options.context,
      color: options.color
    });

    console.log(formattedDiff);
    console.log(`Comparison completed in ${endTime - startTime}ms`);

    // Exit with code 1 if files are different, 0 if identical
    process.exit(diffResult.identical ? 0 : 1);

  } catch (error) {
    console.error(`Error: ${error.message}`);
    process.exit(1);
  }
}

main();